import{_ as s,a as i,o as a,Q as e}from"./chunks/framework.D0YZUKpL.js";const t="/assets/dhcp.DAWRVWvw.png",n="/assets/dns.Cnp6g4qC.png",m=JSON.parse('{"title":"Linux 下 iNode 解决方案","description":"","frontmatter":{"title":"Linux 下 iNode 解决方案","date":"2017-09-19T01:04:54.000Z","tags":["iNode","Linux"],"license":"CC BY-NC 4.0","read":{"text":"2 min read","minutes":1.83,"time":109800,"words":366}},"headers":[{"level":2,"title":"安装","slug":"安装","link":"#安装","children":[]},{"level":2,"title":"运行","slug":"运行","link":"#运行","children":[]},{"level":2,"title":"其他相关","slug":"其他相关","link":"#其他相关","children":[{"level":3,"title":"自动获取 IP","slug":"自动获取-ip","link":"#自动获取-ip","children":[]},{"level":3,"title":"修改 dns","slug":"修改-dns","link":"#修改-dns","children":[]}]}],"relativePath":"posts/inode.md","filePath":"posts/inode.md"}'),l={name:"posts/inode.md"},h=e(`<p>由于学校的 iNode 客户端 Linux 版太古老了，安装起来遇到各种各样的问题。所以就在 github 搜了一搜，看有没有什么开源的 iNode 的替代品。结果就让我找到了！</p><p>开源的 iNode 替代品 <a href="https://github.com/liuqun/njit8021xclient/blob/master/ReadMe.html" target="_blank" rel="noreferrer">njit8021xclient</a>。</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>按照 <a href="https://github.com/liuqun/njit8021xclient/blob/master/Install.html" target="_blank" rel="noreferrer">install.html</a> 编译安装。</p><p>编译的时候注意<strong>第一次</strong>需要<strong>先</strong>在 <code>njit-clinet</code> 项目的根目录下运行命令</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">autoreconf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install</span></span></code></pre></div><p>然后安装说明编译安装就行了。</p><p>不同的 Linux 版本 <code>autoreconf</code> 可能不同，可自行搜索安装。</p><h2 id="运行" tabindex="-1">运行 <a class="header-anchor" href="#运行" aria-label="Permalink to &quot;运行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iwconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #查看网卡</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> njit-client</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 用户名</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 密码</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 网卡</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #可在后面添加 &amp; 符号，使其后台运行。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> njit-client</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 用户名</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 密码</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 网卡</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span></code></pre></div><p>网卡需要输入你电脑连上的那个网卡。有时候是<strong>无线</strong>的网卡，有时候是<strong>有线</strong>的网卡。</p><h2 id="其他相关" tabindex="-1">其他相关 <a class="header-anchor" href="#其他相关" aria-label="Permalink to &quot;其他相关&quot;">​</a></h2><h3 id="自动获取-ip" tabindex="-1">自动获取 IP <a class="header-anchor" href="#自动获取-ip" aria-label="Permalink to &quot;自动获取 IP&quot;">​</a></h3><p>可能还需要设置自动获取 ip，设置方式： 打开网络连接设置。找到设置面板。然后在 IPv4 设置中选择 DHCP 模式。</p><p>如图：</p><p><img src="`+t+`" alt="设置网卡"></p><h3 id="修改-dns" tabindex="-1">修改 dns <a class="header-anchor" href="#修改-dns" aria-label="Permalink to &quot;修改 dns&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#临时修改 dns</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolv.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #修改 nameserver 后面的地址就好了。</span></span></code></pre></div><p>也可以直接在设置面板里面设置 dns，设置如图：</p><p><img src="`+n+'" alt="设置 dns"></p><p>在 Additional DNS servers 后面填上 dns 地址即可。我填的的是阿里提供的 DNS 地址。</p>',21),p=[h];function r(d,o,c,k,g,u){return a(),i("div",null,p)}const b=s(l,[["render",r]]);export{m as __pageData,b as default};
